# Create exactly 100 questions (20 categories * 5 = 100)
assert len(faqs) == 100, f"Expected 100 FAQs, but got {len(faqs)}"

os.makedirs('data', exist_ok=True)
with open('data/faq.csv', mode='w', newline='', encoding='utf-8') as f:
    writer = csv.writer(f)
    writer.writerow(['Question', 'Answer', 'Category'])
    writer.writerows(faqs)

print("Successfully generated data/faq.csv with 100 rows.")
